struct Wallet {
    let privateKey: String
    let publicKey: String
    let address: String
}

class CryptoManager {
    static let shared = CryptoManager()
    
    private init() {}
    
    func generateWallet() -> Wallet {
        let privateKeyData = generatePrivateKey()
        let privateKeyHex = privateKeyData.hexString
        let publicKey = derivePublicKey(from: privateKeyData)
        let address = deriveAddress(from: publicKey)
        
        return Wallet(privateKey: privateKeyHex, publicKey: publicKey, address: address)
    }
    
    private func generatePrivateKey() -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        let result = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        guard result == errSecSuccess else {
            fatalError("Failed to generate random bytes")
        }
        return Data(bytes)
    }
    
    private func derivePublicKey(from privateKey: Data) -> String {
        let hash = SHA256.hash(data: privateKey)
        return Data(hash).hexString
    }
    
    private func deriveAddress(from publicKey: String) -> String {
        guard let data = publicKey.hexData else { return "" }
        let hash = SHA256.hash(data: data)
        let addressData = Data(hash).prefix(20)
        return "0x" + addressData.hexString
    }
    
    func signTransaction(privateKey: String, transaction: Transaction) -> String? {
        guard let privateKeyData = privateKey.hexData else { return nil }
        let transactionData = transaction.serialize()
        
        return signData(data: transactionData, privateKey: privateKeyData)
    }
    
    private func signData(data: Data, privateKey: Data) -> String {
        let hash = SHA256.hash(data: data)
        let hashData = Data(hash)
        
        var combinedData = privateKey
        combinedData.append(hashData)
        let signature = SHA256.hash(data: combinedData)
        
        return Data(signature).hexString
    }
}

struct Transaction {
    let from: String
    let to: String
    let amount: Double
    let nonce: Int
    let gasPrice: Double
    let gasLimit: Int
    
    func serialize() -> Data {
        let jsonDict: [String: Any] = [
            "from": from,
            "to": to,
            "amount": amount,
            "nonce": nonce,
            "gasPrice": gasPrice,
            "gasLimit": gasLimit
        ]
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: jsonDict, options: .sortedKeys) else {
            return Data()
        }
        return jsonData
    }
}

struct SignedTransaction {
