extension Data {
    var hexString: String {
        return map { String(format: "%02x", $0) }.joined()
    }
}

extension String {
    var hexData: Data? {
        var data = Data(capacity: count / 2)
        var buffer = ""
        
        for char in self {
            buffer.append(char)
            if buffer.count == 2 {
                guard let byte = UInt8(buffer, radix: 16) else { return nil }
                data.append(byte)
                buffer = ""
            }
        }
        
        return data
    }
}

